    if (data.length !== expected) {
        throw new RangeError(`decodeInput: sharp raw length=${data.length} != width*height*channels=${expected}`);
    }
    const out = new Float32Array(expected);
    for (let i = 0; i < expected; i++)
        out[i] = data[i] / 255;
